import { useEffect, useMemo, useState } from 'react';
import api from '../api/axios';
import VideoCard from '../components/VideoCard';

function Home() {
  const [videos, setVideos] = useState([]);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchVideos = async () => {
      try {
        const { data } = await api.get('/videos');
        setVideos(data);
      } catch (_error) {
        setVideos([]);
      } finally {
        setLoading(false);
      }
    };

    fetchVideos();
  }, []);

  const filteredVideos = useMemo(() => {
    if (!search.trim()) {
      return videos;
    }
    return videos.filter((video) =>
      `${video.title} ${video.category}`.toLowerCase().includes(search.toLowerCase())
    );
  }, [videos, search]);

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-3">
        <h4 className="mb-0">Browse Videos</h4>
        <input
          className="form-control"
          style={{ maxWidth: 320 }}
          placeholder="Search videos"
          value={search}
          onChange={(event) => setSearch(event.target.value)}
        />
      </div>

      {loading ? (
        <div className="alert alert-info">Loading videos...</div>
      ) : filteredVideos.length === 0 ? (
        <div className="alert alert-warning">No videos found.</div>
      ) : (
        <div className="row g-3">
          {filteredVideos.map((video) => (
            <div className="col-sm-6 col-lg-4" key={video._id}>
              <VideoCard video={video} />
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default Home;
